.darma-loader-darma-research-magnet-comet-dots { --speed: var(--loader-speed, 1s); --accent: var(--loader-color, #f59e0b); --accent-2: var(--loader-secondary-color, #6366f1); width: calc(var(--loader-size, 78px) * 1.35); height: calc(var(--loader-size, 78px) * .52); display: flex; align-items: center; justify-content: space-between; gap: 7px; filter: drop-shadow(0 0 10px color-mix(in srgb, var(--accent) 45%, transparent)); }
.darma-loader-darma-research-magnet-comet-dots span { width: 14%; aspect-ratio: 1; border-radius: 50%; background: var(--accent-2); animation: darma-loader-darma-research-magnet-comet-dots-comet-pull calc(var(--speed) * 1.2) ease-in-out infinite; }
.darma-loader-darma-research-magnet-comet-dots span:nth-child(1) { animation-delay: -.4s; } .darma-loader-darma-research-magnet-comet-dots span:nth-child(2) { animation-delay: -.3s; } .darma-loader-darma-research-magnet-comet-dots span:nth-child(3) { animation-delay: -.2s; } .darma-loader-darma-research-magnet-comet-dots span:nth-child(4) { animation-delay: -.1s; }
.darma-loader-darma-research-magnet-comet-dots span:nth-child(5) { background: var(--accent); box-shadow: 0 0 18px var(--accent); }
@keyframes darma-loader-darma-research-magnet-comet-dots-comet-pull { 0%,100% { transform: translateY(0) scale(.75); opacity: .45; } 45% { transform: translateY(-16px) scale(1.15); opacity: 1; } 70% { transform: translateY(7px) scale(.85); } }

